THE CLAIM:
{
 "title": "Serviceable share ignores timing, overstating Year-1 demand",
 "narrative": "The model sets serviceable reach at 0.55, treating reach as a fixed property. But for data-center electrical gear, demand that invoices in the next 12 months was already specified at design stage, and the entrant's EU compliance stack takes 6-9 months before it can even bid. Demand that is both open and reachable in Year 1 is closer to 0.35, so the Year-1 number is too high.",
 "mechanism": [
  {
   "step": "trigger",
   "text": "Rack-power specs for 2026 capacity were locked before launch.",
   "refs": [
    "ledger:obtainableFactor",
    "ledger:shape.cagr"
   ]
  },
  {
   "step": "propagation",
   "text": "Entrant cannot bid until EU certifications clear in 6-9 months.",
   "refs": [
    "digest:serviceable-benchmark#c13",
    "digest:serviceable-benchmark#c11",
    "profile:Stage"
   ]
  },
  {
   "step": "model-impact",
   "text": "Reach of 0.55 counts demand unreachable in Year 1; effective share near 0.35.",
   "refs": [
    "ledger:serviceableFactor",
    "digest:serviceable-benchmark#c1"
   ]
  }
 ],
 "falsifier": "Three or more EU operator RFQs for rack PDUs in the next two quarters that accept vendors certifying mid-tender and award within 9 months of publication.",
 "category": "model-structure",
 "evidence": []
}

THE LEDGER FACTS IT TARGETS (current values, derivations, bands):
[
 {
  "id": "serviceableFactor",
  "label": "Serviceable share of TAM",
  "kind": "assumption",
  "value": 0.55,
  "unit": "ratio",
  "confidence": "inferred",
  "maturity": "needs-source",
  "dimension": null,
  "dimensionValue": null,
  "sensitivityRange": {
   "low": 0.45,
   "high": 0.65
  },
  "funnelActive": true,
  "derivation": {
   "method": "Reachability assumption",
   "expression": "No public SAM/TAM benchmark for B2B hardware exists; EU cert stack (EN 50600, ecodesign 2019/424, CE/TÜV) justifies < 1.0 but doesn't quantify 0.55"
  },
  "provenance": {
   "rationale": "Assumption leaf — channel + regulatory reach; EU certification barriers documented qualitatively only.",
   "promotionPath": "Bottom-up channel-coverage model (named accounts × reachable share) → sourced serviceable %."
  },
  "evidence": [
   {
    "title": "EU ecodesign requirements for servers and data storage (2019/424)",
    "sourceType": "industry-report",
    "publisher": "EUR-Lex",
    "date": "2019",
    "excerpt": "EU ecodesign and certification requirements gate which demand is regulatory-clear for a new entrant — the qualitative basis of the serviceable haircut.",
    "attached": true
   }
  ]
 }
]

